import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { MapPin, User, Building } from "lucide-react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import Link from "next/link";

export function LoginForm({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div className={cn("flex flex-col gap-6", className)} {...props}>
      <Card>
        <CardHeader className="text-center">
          <CardTitle className="text-xl">Sign Up</CardTitle>
          <CardDescription>Create an account to get started</CardDescription>
        </CardHeader>
        <CardContent>
          <form>
            <div className="grid gap-6">
              <div className="flex flex-col gap-4">
                <Button asChild className="w-full flex items-center justify-center gap-x-2 bg-[#4285F4] text-white hover:bg-[#357AE8]">
                <Link href="/register/customer">
                  <User className="h-5 w-5" />
                  Sign up as a Customer
                </Link>
                </Button>

                <Button asChild className="w-full flex items-center justify-center gap-x-2 bg-[#4285F4] text-white hover:bg-[#357AE8]">
                <Link href="/register/space-partner">
                  <MapPin className="h-5 w-5" />
                  Sign up as a Space Partner
                </Link>
                </Button>

                <Button asChild className="w-full flex items-center justify-center gap-x-2 bg-[#4285F4] text-white hover:bg-[#357AE8]">
                <Link href="/register/enterprise">
                  <Building className="h-5 w-5" />
                  Sign up as an Enterprise
                </Link>
                </Button>
              </div>

              <div className="text-center text-sm">
                Already have an account?{" "}
                <Link href="/login" className="underline underline-offset-4">
                  Log in
                </Link>
              </div>
            </div>
          </form>
        </CardContent>
      </Card>

      <div className="text-muted-foreground *:[a]:hover:text-primary text-center text-xs text-balance *:[a]:underline *:[a]:underline-offset-4">
        By clicking continue, you agree to our <a href="#">Terms of Service</a>{" "}
        and <a href="#">Privacy Policy</a>.
      </div>
    </div>
  );
}
